#include<bits/stdc++.h>
using namespace std;
struct node{
	long long h,c;
}a[1005][1005];
int main(void){
	long long n,m,k,x,y,h,c;
	cin>>n>>m>>k;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			a[i][j].h=0xffffffff;
			a[i][j].c=0;
		}
	}
	for(int i=0;i<k;i++){
		cin>>x>>y>>h>>c;
		if(a[x][y].h>h){
			a[x][y].h=h;
			a[x][y].c=c;
		}
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cout<<a[i][j].c<<' ';
		}
		cout<<endl;
	}
    return false;
}
